func dijkstra(n int, edges [][]int, start int) []int {
    graph := make([][][2]int, n)
    for _, e := range edges {
        graph[e[0]] = append(graph[e[0]], [2]int{e[1], e[2]})
    }
    dist := make([]int, n)
    for i := range dist {
        dist[i] = math.MaxInt32
    }
    dist[start] = 0
    pq := &IntHeap{{0, start}}
    heap.Init(pq)
    for pq.Len() > 0 {
        cur := heap.Pop(pq).([2]int)
        d, u := cur[0], cur[1]
        if d > dist[u] {
            continue
        }
        for _, neighbor := range graph[u] {
            v, w := neighbor[0], neighbor[1]
            if dist[u]+w < dist[v] {
                dist[v] = dist[u] + w
                heap.Push(pq, [2]int{dist[v], v})
            }
        }
    }
    return dist
}

