    const dist = new Array(n).fill(Infinity);
    dist[start] = 0;
    const pq = new MinPriorityQueue({priority: x => x[0]});
    pq.enqueue([0, start]);
    while (!pq.isEmpty()) {
        const [d, u] = pq.dequeue().element;
        if (d > dist[u]) continue;
        for (const [v, w] of graph[u]) {
            if (dist[u] + w < dist[v]) {
                dist[v] = dist[u] + w;
                pq.enqueue([dist[v], v]);
            }
        }
    }
    return dist;
};

