class UnionFind {
private:
    vector<int> parent;
    vector<int> rank_;
public:
    UnionFind(int n) {
        parent.resize(n);
        rank_.resize(n);
        for (int i = 0; i < n; i++) {
            parent[i] = i;
            rank_[i] = 0;
        }
    }
    int find(int x) {
        if (parent[x] != x)
            parent[x] = find(parent[x]);
        return parent[x];
    }
    void unionSet(int x, int y) {
        int px = find(x), py = find(y);
        if (px == py) return;
        if (rank_[px] < rank_[py]) swap(px, py);
        parent[py] = px;
        if (rank_[px] == rank_[py]) rank_[px]++;
    }
    bool connected(int x, int y) {
        return find(x) == find(y);
    }
};

