class Solution {
    unordered_map<long, int> prefix;
    int target;
public:
    int pathSum(TreeNode* root, int targetSum) {
        target = targetSum;
        prefix[0] = 1;
        return dfs(root, 0);
    }
    int dfs(TreeNode* node, long cur) {
        if (!node) return 0;
        cur += node->val;
        int res = prefix.count(cur - target) ? prefix[cur - target] : 0;
        prefix[cur]++;
        res += dfs(node->left, cur) + dfs(node->right, cur);
        prefix[cur]--;
        return res;
    }
};

