class Solution:
    def pathSum(self, root: Optional[TreeNode], targetSum: int) -> int:
        from collections import defaultdict
        prefix = defaultdict(int)
        prefix[0] = 1

        def dfs(node, cur):
            if not node:
                return 0
            cur += node.val
            res = prefix[cur - targetSum]
            prefix[cur] += 1
            res += dfs(node.left, cur) + dfs(node.right, cur)
            prefix[cur] -= 1
            return res

        return dfs(root, 0)

