from collections import deque
from typing import List

# ===== BFS染色法 =====
def is_bipartite_bfs(graph: List[List[int]]) -> bool:
    """BFS染色法判断二分图"""
    n = len(graph)
    color = [-1] * n  # -1未染色, 0和1两种颜色

    for start in range(n):
        if color[start] != -1:
            continue

        queue = deque([start])
        color[start] = 0

        while queue:
            node = queue.popleft()
            for neighbor in graph[node]:
                if color[neighbor] == -1:
                    color[neighbor] = 1 - color[node]
                    queue.append(neighbor)
                elif color[neighbor] == color[node]:
                    return False
    return True

# ===== DFS染色法 =====
def is_bipartite_dfs(graph: List[List[int]]) -> bool:
    """DFS染色法判断二分图"""
    n = len(graph)
    color = [-1] * n

    def dfs(node, c):
        color[node] = c
        for neighbor in graph[node]:
            if color[neighbor] == -1:
                if not dfs(neighbor, 1 - c):
                    return False
            elif color[neighbor] == c:
                return False
        return True

    for i in range(n):
        if color[i] == -1:
            if not dfs(i, 0):
                return False
    return True

