class FenwickTree:
    def __init__(self, n):
        self.n = n
        self.tree = [0] * (n + 1)

    def _lowbit(self, x):
        return x & (-x)

    def update(self, i, delta):
        while i <= self.n:
            self.tree[i] += delta
            i += self._lowbit(i)

    def query(self, i):
        res = 0
        while i > 0:
            res += self.tree[i]
            i -= self._lowbit(i)
        return res

    def range_query(self, left, right):
        return self.query(right) - self.query(left - 1)

# 逆序对统计
def count_inversions(arr):
    sorted_arr = sorted(set(arr))
    rank = {v: i + 1 for i, v in enumerate(sorted_arr)}
    bit = FenwickTree(len(sorted_arr))
    inversions = 0
    for i in range(len(arr) - 1, -1, -1):
        r = rank[arr[i]]
        inversions += bit.query(r - 1)
        bit.update(r, 1)
    return inversions

arr = [3, 1, 4, 2]
