def build_next(pattern):
    m = len(pattern)
    next_arr = [0] * m
    j = 0
    for i in range(1, m):
        while j > 0 and pattern[i] != pattern[j]:
            j = next_arr[j - 1]
        if pattern[i] == pattern[j]:
            j += 1
            next_arr[i] = j
    return next_arr

def kmp_search(text, pattern):
    if not pattern:
        return 0
    n, m = len(text), len(pattern)
    next_arr = build_next(pattern)
    j = 0
    positions = []
    for i in range(n):
        while j > 0 and text[i] != pattern[j]:
            j = next_arr[j - 1]
        if text[i] == pattern[j]:
            j += 1
        if j == m:
            positions.append(i - m + 1)
            j = next_arr[j - 1]
    return positions

text = "ABABDABACDABABCABAB"
pattern = "ABABCABAB"
print(f"匹配位置: {kmp_search(text, pattern)}")  # [10]

class StringHash:
    def __init__(self, s, base=131, mod=10**18 + 9):
        self.n = len(s)
        self.base = base
        self.mod = mod
        self.prefix = [0] * (self.n + 1)
        self.power = [1] * (self.n + 1)
        for i in range(self.n):
            self.power[i + 1] = (self.power[i] * base) % mod
            self.prefix[i + 1] = (self.prefix[i] * base + ord(s[i])) % mod

    def get_hash(self, left, right):
        res = (self.prefix[right + 1] - self.prefix[left] * self.power[right - left + 1]) % self.mod
        return res if res >= 0 else res + self.mod

# Rabin-Karp字符串匹配
def rabin_karp(text, pattern):
    if len(pattern) > len(text):
        return []
    ph = StringHash(pattern)
    th = StringHash(text)
    pattern_hash = ph.get_hash(0, len(pattern) - 1)
    positions = []
    for i in range(len(text) - len(pattern) + 1):
        if th.get_hash(i, i + len(pattern) - 1) == pattern_hash:
            if text[i:i + len(pattern)] == pattern:
                positions.append(i)
    return positions

print(f"匹配位置: {rabin_karp('ABABDABACDABABCABAB', 'ABABCABAB')}")

def sieve_eratosthenes(n):
    is_prime = [True] * (n + 1)
    is_prime[0] = is_prime[1] = False
    for i in range(2, int(n**0.5) + 1):
        if is_prime[i]:
            for j in range(i * i, n + 1, i):
                is_prime[j] = False
    return [i for i in range(2, n + 1) if is_prime[i]]

def fast_pow(base, exp, mod=None):
    result = 1
    while exp > 0:
        if exp & 1:
            result = result * base if mod is None else (result * base) % mod
        base = base * base if mod is None else (base * base) % mod
        exp >>= 1
    return result

print(f"2^10 = {fast_pow(2, 10)}")  # 1024
print(f"2^100 mod 1000000007 = {fast_pow(2, 100, 1000000007)}")

class TrieNode:
    def __init__(self):
        self.children = {}
        self.is_end = False
        self.count = 0

class Trie:
    def __init__(self):
        self.root = TrieNode()

    def insert(self, word):
        node = self.root
        for char in word:
            if char not in node.children:
                node.children[char] = TrieNode()
            node = node.children[char]
            node.count += 1
        node.is_end = True

    def starts_with(self, prefix):
        node = self.root
        for char in prefix:
            if char not in node.children:
                return []
            node = node.children[char]
        results = []
        self._dfs(node, prefix, results)
        return results

    def _dfs(self, node, prefix, results):
        if node.is_end:
            results.append(prefix)
        for char, child in node.children.items():
            self._dfs(child, prefix + char, results)

# 最大异或值
class XorTrie:
    def __init__(self):
        self.root = {}

    def insert(self, num):
        node = self.root
        for i in range(31, -1, -1):
            bit = (num >> i) & 1
            if bit not in node:
                node[bit] = {}
            node = node[bit]

    def max_xor(self, num):
        if not self.root:
            return -1
        node = self.root
        result = 0
        for i in range(31, -1, -1):
            bit = (num >> i) & 1
            opposite = 1 - bit
            if opposite in node:
                result |= (1 << i)
                node = node[opposite]
            else:
                node = node[bit]
        return result

def find_max_xor(nums):
    trie = XorTrie()
    trie.insert(nums[0])
    max_result = 0
    for num in nums[1:]:
        max_result = max(max_result, trie.max_xor(num))
        trie.insert(num)
    return max_result

nums = [3, 10, 5, 25, 2, 8]
print(f"最大异或值: {find_max_xor(nums)}")  # 28
